// Select random topic for content generation
const topics = [
  "саморазвитие и личностный рост",
  "продуктивность и тайм-менеджмент",
  "здоровый образ жизни",
  "карьера и профессиональное развитие",
  "финансовая грамотность",
  "творчество и креативность",
  "отношения и коммуникация",
  "путешествия и новые впечатления"
];

const randomTopic = topics[Math.floor(Math.random() * topics.length)];

return {
  json: {
    topic: randomTopic,
    timestamp: new Date().toISOString()
  }
};

// Parse AI response and prepare for VK
const aiResponse = $json.choices?.[0]?.message?.content || $json.message || "";

// Extract message (remove quotes if present)
let message = aiResponse.trim();
if (message.startsWith('"') && message.endsWith('"')) {
  message = message.slice(1, -1);
}

// Configuration
const owner_id = "-YOUR_GROUP_ID"; // Replace with your VK group ID
const attachments = ""; // Add attachments if needed

return {
  json: {
    owner_id: owner_id,
    message: message,
    attachments: attachments,
    timestamp: new Date().toISOString(),
    topic: $json.topic || "general"
  }
};

// Fallback content generation if AI is not available
const topic = $json.topic || "саморазвитие";

const contentByTopic = {
  "саморазвитие и личностный рост": [
    "🌱 Каждый день - это возможность стать лучшей версией себя. Что вы сделали сегодня для своего роста? #саморазвитие #личностныйрост #мотивация",
    "💪 Выходите из зоны комфорта! Именно там начинается настоящий рост. #развитие #успех #мотивация"
  ],
  "продуктивность и тайм-менеджмент": [
    "⏰ Секрет продуктивности: фокус на главном, а не на срочном. Расставьте приоритеты правильно! #продуктивность #тайм менеджмент #эффективность",
    "📊 Планируйте день с вечера - и утро станет продуктивнее в разы! #планирование #продуктивность #успех"
  ],
  "здоровый образ жизни": [
    "🏃‍♂️ Здоровье - это не цель, а образ жизни. Начните с малого: 10 минут зарядки каждое утро! #зож #здоровье #спорт",
    "🥗 Правильное питание = ясный ум + энергия на весь день. Заботьтесь о себе! #зож #правильноепитание #здоровье"
  ],
  "карьера и профессиональное развитие": [
    "🎯 Инвестируйте в свои навыки - это лучшая инвестиция в будущее. Что вы изучаете сейчас? #карьера #развитие #обучение",
    "💼 Успешная карьера строится на постоянном обучении и адаптации. Будьте гибкими! #карьера #профессионализм #рост"
  ],
  "финансовая грамотность": [
    "💰 Финансовая свобода начинается с финансовой грамотности. Учитесь управлять деньгами! #финансы #инвестиции #финансоваяграмотность",
    "📈 Правило 50/30/20: 50% на нужды, 30% на желания, 20% на сбережения. Попробуйте! #финансы #планирование #накопления"
  ],
  "творчество и креативность": [
    "🎨 Креативность - это мышца, которую нужно тренировать. Создавайте что-то новое каждый день! #творчество #креативность #искусство",
    "✨ Не бойтесь экспериментировать! Лучшие идеи рождаются за пределами привычного. #креатив #идеи #вдохновение"
  ],
  "отношения и коммуникация": [
    "💬 Качество отношений определяет качество жизни. Инвестируйте время в близких людей! #отношения #общение #любовь",
    "🤝 Умение слушать важнее умения говорить. Будьте внимательны к людям! #коммуникация #отношения #эмпатия"
  ],
  "путешествия и новые впечатления": [
    "✈️ Путешествия расширяют горизонты и меняют мировоззрение. Куда вы мечтаете поехать? #путешествия #приключения #мир",
    "🌍 Новые места = новые впечатления = новый вы. Исследуйте мир! #путешествия #открытия #впечатления"
  ]
};

// Find matching content or use general
const matchingContent = Object.keys(contentByTopic).find(key => topic.includes(key));
const contentArray = matchingContent ? contentByTopic[matchingContent] : [
  "🚀 Каждый день - это новая возможность! Используйте её по максимуму! #мотивация #успех #развитие",
  "💡 Верьте в себя и свои возможности. Вы способны на большее! #мотивация #вера #успех"
];

const randomMessage = contentArray[Math.floor(Math.random() * contentArray.length)];

const owner_id = "-YOUR_GROUP_ID"; // Replace with your VK group ID

return {
  json: {
    owner_id: owner_id,
    message: randomMessage,
    attachments: "",
    timestamp: new Date().toISOString(),
    topic: topic
  }
};

// Validate content before posting
const message = $json.message;
const owner_id = $json.owner_id;

const errors = [];

if (!message || message.trim().length === 0) {
  errors.push("Message cannot be empty");
}

if (message.length > 4096) {
  errors.push("Message exceeds maximum length of 4096 characters");
}

if (!owner_id) {
  errors.push("Owner ID is required");
}

// Check for forbidden words (customize as needed)
const forbiddenWords = ["спам", "реклама без согласия"];
const lowerMessage = message.toLowerCase();
const foundForbidden = forbiddenWords.filter(word => lowerMessage.includes(word));

if (foundForbidden.length > 0) {
  errors.push(`Found forbidden words: ${foundForbidden.join(", ")}`);
}

if (errors.length > 0) {
  return {
    json: {
      valid: false,
      errors: errors,
      original_data: $json
    }
  };
}

return {
  json: {
    valid: true,
    ...($json)
  }
};

// Handle validation errors
const errors = $json.errors || [];
const errorMessage = errors.join(", ");

console.error("Validation failed:", errorMessage);

return {
  json: {
    status: "validation_failed",
    errors: errors,
    timestamp: new Date().toISOString(),
    original_data: $json.original_data
  }
};

// Log successful post
const postId = $json.response?.post_id;
const message = $json.message;
const topic = $json.topic;

console.log(`✅ Successfully posted to VK. Post ID: ${postId}`);

return {
  json: {
    status: "success",
    post_id: postId,
    message: message,
    topic: topic,
    timestamp: new Date().toISOString(),
    vk_response: $json.response
  }
};

// Log error
const error = $json.response?.error || $json.error || "Unknown error";
const message = $json.message;

console.error(`❌ Failed to post to VK. Error: ${JSON.stringify(error)}`);

return {
  json: {
    status: "failed",
    error: error,
    message: message,
    timestamp: new Date().toISOString(),
    vk_response: $json.response
  }
};
